import Foundation
import CoreBluetooth

// 注意：对外接口，不能在字典中带枚举，否则OC无法处理
// 如果消息的 object 不为空则表示当前车辆对象 VehiclePresenter

// 车控SDK消息通知定义
@objc(XPVehicleNotification)
public class VehicleNotification : NSObject {
    @objc static public let BLESysStateChanged: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationBLESysStateChanged")

    @objc static public let BLEConnectStateChanged: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationBLEConnectStateChanged")

    @objc static public let BleConnectError: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationBleConnectError")

    @objc static public let MQTTConnectStateChanged: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationMQTTConnectStateChanged")

    @objc static public let VehicleStartService: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationVehicleStartService")

    @objc static public let BleDidReadRssi: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationBleDidReadRssi")

    @objc static public let BleCDUAccountLoginState: NSNotification.Name = NSNotification.Name(rawValue: "XPBleCDUAccountLoginState")

    @objc static public let CallBackConnectAuthError: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationCallBackConnectAuthError")

    @objc static public let DigitalKeyStateChanged: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationDigitalKeyStateChanged")

    @objc static public let DigitalKeyCreateKey: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationDigitalKeyCreateKey")

    @objc static public let DigitalKeyReceiveKeyMessageSuccess: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationDigitalKeyReceiveKeyMessage")

    @objc static public let CarKeyNeedRefesh: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationCarKeyNeedRefesh")

    @objc static public let CarKeyPassExceptionReport: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationCarKeyPassExceptionReport")

    @objc static public let CarKeySessionExceptionReport: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationCarKeySessionExceptionReport")

    @objc static public let CarKeyPassClear: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationCarKeyPassClear")

    @objc static public let myVehicles: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationMyVehicles")
    @objc static public let AutoLockResult: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationAutoLockResult")

    // object: VehicleExtInfo
    @objc static public let VehicleExtInfoUpdated: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationVehicleExtInfoUpdated")

    @objc static public let ParkStateChanged: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationParkStateChanged")
    @objc static public let ParkCollisionStateChanged: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationParkCollisionStateChanged")

    @objc static public let ParkControlStateChanged: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationParkControlStateChanged")

    @objc static public let tboxRunStateNotification: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationTboxRunStateNotification")

    @objc static public let rescueKeyConnectFailedMoreTimeNotification: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationRescueKeyConnectFailedMoreTimeNotification")

    @objc static public let rescueBleConnectStateChanged: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationTboxRescueBleConnectStateChanged")

    @objc static public let CameraStateChanged: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationCameraStateChanged")

    @objc static public let kMyDigitalKeyListRequestSuccess: NSNotification.Name = NSNotification.Name(rawValue: "myDigitalKeyListRequestSuccess")

    @objc static public let kCarKeyFlowDidStart: NSNotification.Name = NSNotification.Name(rawValue: "carKeyFlowDidStart")

    @objc static public let kCarKeyFlowDidEnd: NSNotification.Name = NSNotification.Name(rawValue: "carKeyFlowDidEnd")

    @objc static public let kCameraErrorNotification: NSNotification.Name = NSNotification.Name(rawValue: "CarControlCameraErrorNotification")

    // 收到大屏断开蓝牙信号通知
    @objc static public let kReceiveIBCMRequestDisconnectBle: NSNotification.Name = NSNotification.Name(rawValue: "kReceiveIBCMRequestDisconnectBle")
    // 从无网恢复到有网通知
    @objc static public let NetworkResume: NSNotification.Name = NSNotification.Name(rawValue: "XPVehicleNotificationNetworkResume")
    // CarKey舒适进入开关的
    @objc static public let kGetCarKeyPassiveEntrySwitchResult: NSNotification.Name = NSNotification.Name(rawValue: "getCarKeyPassiveEntrySwitchResult")

}

@objc(XPMQTTConnectionNotiObject)
public class MQTTConnectionNotiObject : NSObject {
    @objc public let connectState: MQTTConnectionState

    init(connectState: MQTTConnectionState) {
        self.connectState = connectState
    }

    public override var description: String {
        return "MQTTConnectionNotiObject:(\(connectState.rawValue)) ." + connectState.name
    }
}

@objc(XPBLESysStateNotiObject)
public class BLESysStateNotiObject : NSObject {
    @objc public let bleSysState: BLESysState

    init(bleSysState: BLESysState) {
        self.bleSysState = bleSysState
    }

    public override var description: String {
        return "BLEConnectionNotiObject:(bleSysState:\(bleSysState.rawValue)) ." + bleSysState.name
    }
}

@objc(XPAutoLockNotiObject)
public class AutoLockNotiObject : NSObject {
    @objc public let result: AutoLockResult

    init(result: AutoLockResult) {
        self.result = result
    }

    public override var description: String {
        return "AutoLockNotiObject:(result:\(result.rawValue)) ." + result.name
    }
}

@objc(XPBLEConnectionNotiObject)
public class BLEConnectionNotiObject : NSObject {
    @objc public let vin: String                // 车架号
    @objc public let connectState: BLEConnectionState

    init(vin: String, connectState: BLEConnectionState) {
        self.vin = vin
        self.connectState = connectState
    }

    public override var description: String {
        return "BLEConnectionNotiObject:(vin:\(vin) state:\(connectState.rawValue)) ." + connectState.name
    }
}

@objc(XPBLEConnectErrorCode)
public enum BLEConnectErrorCode : Int, CustomStringConvertible {

    case timeout = 0       // 超时
    case unconnectable = 1 // 连接不可用：如蓝牙被其他设备连接
    case other = 2         // 其他
    case authFailue = 3    // 鉴权失败

    public var name: String {
        switch self {
        case .timeout: return "timeout"
        case .unconnectable: return "unconnectable"
        case .other: return "other"
        case .authFailue: return "authFailue"

        default: return "Unknown"
        }
    }

    public var description: String {
        return "BLEConnectErrorCode:(\(rawValue)) ." + name
    }
}

@objc(XPBLEConnectErrorNotiObject)
public class BLEConnectErrorNotiObject : NSObject {
    @objc public let macAddress: String                // 车架号
    @objc public let errorState: BLEConnectErrorCode

    init(macAddress: String, errorState: BLEConnectErrorCode) {
        self.macAddress = macAddress
        self.errorState = errorState
    }

    public override var description: String {
        return "BLEConnectionNotiObject:(macAddress:\(macAddress) state:\(errorState.rawValue)) ." + errorState.name
    }
}

// 车辆状态变更
@objc(XPVehicleStateNotiObject)
public class VehicleStateNotiObject : NSObject {
    public let fullVehicleState: VehicleState // 完整车态数据
    public let diffVehicleState: VehicleState // 当前变化的车态数据（增量数据），如果是左门打开，那么就只有
                                       //  diffVehicleState.door.driver_door_ajar_st 是有效值 .open(XPVehicleDoorAjarStateOpen)，
    @objc public var fullVehicleDict: NSDictionary = [:]
    @objc public var diffVehicleDict: NSDictionary = [:]

    @objc public let channel: VehicleChannel // 指示该次车态变化来自蓝牙或MQTT通道

    @objc public init(fullVehicleState: VehicleState, diffVehicleState: VehicleState, channel: VehicleChannel) {

        self.fullVehicleState = fullVehicleState
        self.diffVehicleState = diffVehicleState

        self.channel = channel

        var fullDict = fullVehicleState.toDict()
        var diffDict = diffVehicleState.toDict()


        super.init()

        self.makeLocalState(dict: &fullDict)
        self.makeLocalState(dict: &diffDict)

        self.fullVehicleDict = fullDict as NSDictionary
        self.diffVehicleDict = diffDict as NSDictionary

    }

    private func makeLocalState(dict: inout [String: Any]) {
        if let extDict = dict["ext"] as? [String: Any],
           let repairMode = extDict["repairMode"] {
