extension BLEKeyV3Parser {
    override func handleCanEvent(msg: BleCanMessage) {
        super.handleCanEvent(msg: msg)
        guard let event = msg.canEvent else { return }
        guard let eventType = event.eventType else { return }
        switch eventType {
        case .commonResponse:
            handleCommonResponse(event: event)
        case .carControlResult:
            handleCarControlResult(event: event)
        case .selfCalibration:
            handleSelfCalibration(event: event)
        case .rssiCollect:
            handleRssiCollect(event: event)
        case .parkingControl:
            handleParkingControlState(event: event)
        case .tboxRunState:
            handleTboxRunStateEvent(event: event)
        case .rtAuthResult:
            handleRtAuthResult(event: event)
        case .rtNotification:
            handleRtNotification(event: event)
        default: break
        }
    }

    func handleSelfCalibration(event: CanEvent) {
        v3Delegate?.didReceiveSelfCalirationResult(reseult: Int(event.result ?? -1), resultLen: Int(event.resultLen ?? -1), resultData: event.resultData ?? "", direction: Int(event.direction ?? -1), distance: Int(event.distance ?? -1), deviceModel: event.deviceModel ?? "")
    }

    func handleRssiCollect(event: CanEvent) {
        v3Delegate?.didReceiveRssiCollectResult(reseult: Int(event.result ?? -1), direction: Int(event.direction ?? -1), distance: Int(event.distance ?? -1), deviceModel: event.deviceModel ?? "")
    }

    func handleParkingControlState(event: CanEvent) {
        v3Delegate?.didReceiveParkingControlState(result: event.parkingControlState ?? 0)
    }

    func handleCommonResponse(event: CanEvent) {
        delegate?.didReceiveAuthResult(authResult: Int(event.commonStatus ?? -1), failedReason: Int(event.commonErrorCode ?? -1))
    }

    func handleCarControlResult(event: CanEvent) {
        carControlDelegate?.didReceiveCanEventCarControlResult(controlId: Int(event.controlId ?? -1), result: Int(event.controlState ?? -1))
    }

    func handleTboxRunStateEvent(event: CanEvent) {
        v3Delegate?.didReceiveTboxRunStateEvent(result: event.status ?? 0)
    }

    func handleRtAuthResult(event: CanEvent) {
        v3Delegate?.didReceiveRtAuthResult(result: event.rtAuthResult ?? -1, errorCode: event.rtAuthErrorCode ?? -1)
    }

    func handleRtNotification(event: CanEvent) {
        v3Delegate?.didReceiveRtNotification(pollingResult: event.rtPollingResult ?? -1)
    }
}

